/**
 * Register all problems RPC routes.
 *
 * Routes: GET /vista/problems/rpc/:slug
 *         GET /vista/problems/rpcs  (catalog listing)
 */
export default async function problemsRoutes(server: FastifyInstance): Promise<void> {
  // -- Catalog listing -------------------------------------------
  server.get('/vista/problems/rpcs', async () => {
    return {
      ok: true,
      domain: 'problems',
      count: 25,
      rpcs: PROBLEMS_RPCS,
    };
  });

  // -- Phase 568: Wired priority problem routes ------------------

  /** ORWPCE PCE4NOTE -- Get PCE encounter data for a note (read) */
  server.get('/vista/problems/for-note', async (request: FastifyRequest, reply: FastifyReply) => {
    await requireSession(request, reply);
    const dfn = (request.query as any)?.dfn;
    const noteIen = (request.query as any)?.noteIen;
    if (!dfn) return reply.status(400).send({ ok: false, error: 'dfn query parameter required' });
    if (!noteIen)
      return reply.status(400).send({ ok: false, error: 'noteIen query parameter required' });
    try {
      const lines = await safeCallRpc('ORWPCE PCE4NOTE', [String(dfn), String(noteIen)]);
      return reply.send({
        ok: true,
        source: 'vista',
        data: lines,
        rpcUsed: ['ORWPCE PCE4NOTE'],

      });
    } catch (err: any) {
      log.warn('ORWPCE PCE4NOTE failed', { err: err?.message || String(err) });
      return reply.code(502).send({
        ok: false,
        source: 'vista',
        error: err?.message || 'RPC call failed',
        rpcUsed: ['ORWPCE PCE4NOTE'],
      });
    }
  });

  /** Problem list -- ORQQPL PROBLEM LIST (primary) + VE PROBLEM LIST (supplement) */
  server.get('/vista/problems/list', async (request: FastifyRequest, reply: FastifyReply) => {
    await requireSession(request, reply);
    const dfn = (request.query as any)?.dfn;
    if (!dfn) return reply.status(400).send({ ok: false, error: 'dfn query parameter required' });
    const status = (request.query as any)?.status || 'A'; // A=active, I=inactive, B=both
    const rpcUsed: string[] = [];
    let primaryData: string[] = [];
    let supplementData: string[] = [];

    // Primary: ORQQPL PROBLEM LIST
    try {
      rpcUsed.push('ORQQPL PROBLEM LIST');
      primaryData = await safeCallRpc('ORQQPL PROBLEM LIST', [String(dfn), String(status)]);
    } catch (err: any) {
      log.warn('ORQQPL PROBLEM LIST failed', { err: err?.message || String(err) });
    }

    // Supplement: VE PROBLEM LIST (reads from File #9000011 directly)
    try {
      rpcUsed.push('VE PROBLEM LIST');
      supplementData = await safeCallRpc('VE PROBLEM LIST', [String(dfn), String(status)]);
    } catch (err: any) {
      log.warn('VE PROBLEM LIST failed (supplement)', { err: err?.message || String(err) });
    }

    if (primaryData.length === 0 && supplementData.length === 0) {
      return reply.code(502).send({
        ok: false,
        source: 'vista',
        error: 'Both ORQQPL PROBLEM LIST and VE PROBLEM LIST returned no data',
        rpcUsed,
      });
    }

    return reply.send({
      ok: true,
      source: 'vista',
      data: primaryData,
      supplement: supplementData.length > 0 ? supplementData : undefined,
      rpcUsed,
    });
  });

  /** Add problem -- VE PROBLEM ADD (primary) with ORQQPL ADD SAVE fallback */
  const AddProblemSchema = z.object({
    dfn: z.string().min(1, 'dfn required'),
    icdCode: z.string().min(1, 'icdCode required'),
    narrative: z.string().min(1, 'narrative required'),
    status: z.enum(['A', 'I']).optional(),
    onset: z.string().optional(),
    providerIen: z.string().optional(),
  });

  server.post('/vista/problems/add', async (request: FastifyRequest, reply: FastifyReply) => {
    const session = await requireSession(request, reply);
    const body = (request.body as any) || {};
    const parsed = AddProblemSchema.safeParse(body);
    if (!parsed.success) {
      return reply
        .status(400)
        .send({ ok: false, error: 'Validation failed', details: parsed.error.issues });
    }

    const { dfn, icdCode, narrative, status: probStatus, onset, providerIen } = parsed.data;
    const duz = providerIen || (session as any)?.duz || '';
    const rpcUsed: string[] = [];

    // Primary: VE PROBLEM ADD (custom ZVEPLW.m routine, writes to File #9000011)
    try {
      rpcUsed.push('VE PROBLEM ADD');
      const lines = await safeCallRpc('VE PROBLEM ADD', [dfn, icdCode, narrative, probStatus || 'A', onset || '', duz]);
      const firstLine = (lines || [])[0] || '';
      const [okFlag = '0', problemIen = '', message = ''] = firstLine.split('^');
      if (okFlag === '1' && problemIen) {
        return reply.status(201).send({
          ok: true,
          source: 'vista',
          status: 'added',
          problemIen,
          rpcUsed,
          message: message || 'Problem added via VE PROBLEM ADD',
        });
      }
      if (firstLine.startsWith('-1') || firstLine.includes('ERROR')) {
        throw new Error(`VE PROBLEM ADD returned: ${firstLine}`);
      }
      throw new Error(`VE PROBLEM ADD returned unexpected: ${firstLine || '(empty)'}`);
    } catch (primaryErr: any) {
      log.warn('VE PROBLEM ADD failed, trying ORQQPL ADD SAVE fallback', { err: primaryErr?.message });
    }

    // Fallback: ORQQPL ADD SAVE
    try {
      rpcUsed.push('ORQQPL ADD SAVE');
      const lines = await safeCallRpc('ORQQPL ADD SAVE', [dfn]);
      const result = (lines || [])[0] || '';
      if (result && !result.startsWith('-1') && !result.includes('ERROR')) {
        return reply.status(201).send({
          ok: true,
          source: 'vista',
          status: 'added',
          problemIen: result.split('^')[0]?.trim() || '',
          rpcUsed,
        });
      }
      throw new Error(`ORQQPL ADD SAVE returned: ${result || '(empty)'}`);
    } catch (err: any) {
      log.warn('ORQQPL ADD SAVE also failed', { err: err?.message || String(err) });
      return reply.code(502).send({
        ok: false,
        source: 'vista',
        error: err?.message || 'Problem add RPC failed',
        rpcUsed,
      });
    }
  });

  /** Edit problem -- VE PROBLEM EDIT (ZVEPLW.m) */
  const EditProblemSchema = z.object({
    dfn: z.string().min(1, 'dfn required'),
    problemIen: z.string().min(1, 'problemIen required'),
    field: z.string().min(1, 'field required'),
    value: z.string(),
  });

  server.post('/vista/problems/edit', async (request: FastifyRequest, reply: FastifyReply) => {
    await requireSession(request, reply);
    const body = (request.body as any) || {};
    const parsed = EditProblemSchema.safeParse(body);
    if (!parsed.success) {
      return reply
        .status(400)
        .send({ ok: false, error: 'Validation failed', details: parsed.error.issues });
    }

    const { problemIen, dfn, field, value } = parsed.data;
    const rpcUsed = ['VE PROBLEM EDIT'];

    try {
      const lines = await safeCallRpc('VE PROBLEM EDIT', [problemIen, dfn, field, value]);
      const firstLine = (lines || [])[0] || '';
      const [okFlag = '0', , message = ''] = firstLine.split('^');
      if (okFlag === '1') {
        return reply.send({
          ok: true,
          source: 'vista',
          status: 'edited',
          problemIen,
          rpcUsed,
          message: message || 'Problem edited via VE PROBLEM EDIT',
        });
      }
      throw new Error(`VE PROBLEM EDIT returned: ${firstLine || '(empty)'}`);
    } catch (err: any) {
      log.warn('VE PROBLEM EDIT failed', { err: err?.message || String(err) });
      return reply.code(502).send({
        ok: false,
        source: 'vista',
        error: err?.message || 'Problem edit RPC failed',
        rpcUsed,
      });
    }
  });

  /** Remove (inactivate) problem -- VE PROBLEM REMOVE (ZVEPLW.m) */
  const RemoveProblemSchema = z.object({
    dfn: z.string().min(1, 'dfn required'),
    problemIen: z.string().min(1, 'problemIen required'),
    reason: z.string().optional(),
  });

  server.post('/vista/problems/remove', async (request: FastifyRequest, reply: FastifyReply) => {
    await requireSession(request, reply);
    const body = (request.body as any) || {};
    const parsed = RemoveProblemSchema.safeParse(body);
    if (!parsed.success) {
      return reply
        .status(400)
        .send({ ok: false, error: 'Validation failed', details: parsed.error.issues });
    }

    const { problemIen, dfn, reason } = parsed.data;
    const rpcUsed = ['VE PROBLEM REMOVE'];

    try {
      const lines = await safeCallRpc('VE PROBLEM REMOVE', [problemIen, dfn, reason || '']);
      const firstLine = (lines || [])[0] || '';
      const [okFlag = '0', , message = ''] = firstLine.split('^');
      if (okFlag === '1') {
        return reply.send({
          ok: true,
          source: 'vista',
          status: 'removed',
          problemIen,
          rpcUsed,
          message: message || 'Problem inactivated via VE PROBLEM REMOVE',
        });
      }
      throw new Error(`VE PROBLEM REMOVE returned: ${firstLine || '(empty)'}`);
    } catch (err: any) {
      log.warn('VE PROBLEM REMOVE failed', { err: err?.message || String(err) });
      return reply.code(502).send({
        ok: false,
        source: 'vista',
        error: err?.message || 'Problem remove RPC failed',
        rpcUsed,
      });
    }
  });

  // -- Phase 578 (Wave 42): Wired RPC endpoints -----------------

  /** Generic RPC caller for problem domain -- DFN-based reads. */
  async function callProblemRpc(
    rpcName: string,
    request: FastifyRequest,
    reply: FastifyReply,
    paramBuilder?: (q: any) => string[]
  ) {
    await requireSession(request, reply);
    const q = request.query as any;
    const params = paramBuilder ? paramBuilder(q) : q?.dfn ? [String(q.dfn)] : [];
    try {
      const lines = await safeCallRpc(rpcName, params);
      return reply.send({
        ok: true,
        source: 'vista',
        rpcUsed: [rpcName],
        data: lines,

      });
    } catch (err: any) {
      log.warn(`${rpcName} failed`, { err: err?.message });
      return reply.code(502).send({
        ok: false,
        source: 'vista',
        error: err?.message || 'RPC call failed',
        rpcUsed: [rpcName],
      });
    }
  }

  server.get('/vista/problems/rpc/orqqpl-add-save', (req, rep) =>
    callProblemRpc('ORQQPL ADD SAVE', req, rep, (q) => [q?.dfn || '', q?.data || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-audit-hist', (req, rep) =>
    callProblemRpc('ORQQPL AUDIT HIST', req, rep, (q) => [q?.dfn || '', q?.probIen || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-check-dup', (req, rep) =>
    callProblemRpc('ORQQPL CHECK DUP', req, rep, (q) => [q?.dfn || '', q?.term || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-clin-filter-list', (req, rep) =>
    callProblemRpc('ORQQPL CLIN FILTER LIST', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-clin-srch', (req, rep) =>
    callProblemRpc('ORQQPL CLIN SRCH', req, rep, (q) => [q?.term || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-delete', (req, rep) =>
    callProblemRpc('ORQQPL DELETE', req, rep, (q) => [q?.dfn || '', q?.probIen || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-detail', (req, rep) =>
    callProblemRpc('ORQQPL DETAIL', req, rep, (q) => [q?.dfn || '', q?.probIen || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-edit-load', (req, rep) =>
    callProblemRpc('ORQQPL EDIT LOAD', req, rep, (q) => [q?.probIen || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-edit-save', (req, rep) =>
    callProblemRpc('ORQQPL EDIT SAVE', req, rep, (q) => [q?.probIen || '', q?.data || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-init-pt', (req, rep) =>
    callProblemRpc('ORQQPL INIT PT', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-init-user', (req, rep) =>
    callProblemRpc('ORQQPL INIT USER', req, rep, () => [])
  );

  server.get('/vista/problems/rpc/orqqpl-prob-comments', (req, rep) =>
    callProblemRpc('ORQQPL PROB COMMENTS', req, rep, (q) => [q?.dfn || '', q?.probIen || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-problem-list', (req, rep) =>
    callProblemRpc('ORQQPL PROBLEM LIST', req, rep, (q) => [q?.dfn || '', q?.status || 'A'])
  );

  server.get('/vista/problems/rpc/orqqpl-problem-ntrt-bulletin', (req, rep) =>
    callProblemRpc('ORQQPL PROBLEM NTRT BULLETIN', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-prov-filter-list', (req, rep) =>
    callProblemRpc('ORQQPL PROV FILTER LIST', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-provider-list', (req, rep) =>
    callProblemRpc('ORQQPL PROVIDER LIST', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-replace', (req, rep) =>
    callProblemRpc('ORQQPL REPLACE', req, rep, (q) => [
      q?.dfn || '',
      q?.probIen || '',
      q?.newIcd || '',
    ])
  );

  server.get('/vista/problems/rpc/orqqpl-saveview', (req, rep) =>
    callProblemRpc('ORQQPL SAVEVIEW', req, rep, (q) => [q?.view || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-serv-filter-list', (req, rep) =>
    callProblemRpc('ORQQPL SERV FILTER LIST', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-srvc-srch', (req, rep) =>
    callProblemRpc('ORQQPL SRVC SRCH', req, rep, (q) => [q?.term || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-update', (req, rep) =>
    callProblemRpc('ORQQPL UPDATE', req, rep, (q) => [q?.dfn || '', q?.data || ''])
  );

  server.get('/vista/problems/rpc/orqqpl-user-prob-cats', (req, rep) =>
    callProblemRpc('ORQQPL USER PROB CATS', req, rep, () => [])
  );

  server.get('/vista/problems/rpc/orqqpl-user-prob-list', (req, rep) =>
    callProblemRpc('ORQQPL USER PROB LIST', req, rep)
  );

  server.get('/vista/problems/rpc/orqqpl-verify', (req, rep) =>
    callProblemRpc('ORQQPL VERIFY', req, rep, (q) => [q?.dfn || '', q?.probIen || ''])
  );

  server.get('/vista/problems/rpc/orqqpl4-lex', (req, rep) =>
    callProblemRpc('ORQQPL4 LEX', req, rep, (q) => [q?.term || '', q?.count || '20'])
  );
}
